// Finalization registry for GLibDir
const glibdirRegistry = new FinalizationRegistry((ptr: string) => {
  fetch(apiConfig.fullBaseUrl + '/GLib/Dir/ptr,' + ptr + '/free')
    .catch(err => console.error('Failed to free GLibDir:', ptr, err));
});

